// REQ-001 (CC-0098): Default zero-valued sub-fields of spec.logging.
// When the pointer is nil, materialize the production baseline so downstream
// reconciler code dereferences spec.logging unconditionally (mirrors the
// Resources-when-nil pattern below). When non-nil, partial-fill zero values
// (Format, Level) but leave Debug alone — bool's zero value is indistinguishable
// from explicit false, so we cannot safely override it (mirrors the
// UWSGISpec.HTTPKeepAlive carve-out documented above).
if obj.Spec.Logging == nil {
    obj.Spec.Logging = &LoggingSpec{
        Format: "text",
        Level:  "INFO",
        Debug:  false,
    }
} else {
    if obj.Spec.Logging.Format == "" {
        obj.Spec.Logging.Format = "text"
    }
    if obj.Spec.Logging.Level == "" {
        obj.Spec.Logging.Level = "INFO"
    }
}

// effectiveLogging returns the LoggingSpec to use for config rendering,
// materializing the production defaults when spec.logging is nil. The
// defaulting webhook materializes the same baseline at admission, so this
// fallback only matters when a CR bypasses the webhook (e.g. a pre-existing
// CR observed by a freshly upgraded operator). Mirrors the UWSGISpec
// nil-tolerance pattern at reconcile_deployment.go:317 (CC-0098, REQ-001).
func effectiveLogging(spec *keystonev1alpha1.LoggingSpec) keystonev1alpha1.LoggingSpec {
    out := keystonev1alpha1.LoggingSpec{Format: "text", Level: "INFO"}
    if spec == nil {
        return out
    }
    out = *spec
    if out.Format == "" {
        out.Format = "text"
    }
    if out.Level == "" {
        out.Level = "INFO"
    }
    return out
}

// renderDefaultLogLevels formats PerLoggerLevels as oslo.log's
// default_log_levels CSV ("name=LEVEL,..."), with keys sorted alphabetically
// so the rendered keystone.conf — and therefore the immutable ConfigMap
// content hash — is independent of Go's randomized map iteration order
// (CC-0098, REQ-005). Returns "" for empty input so the caller can omit the
// key entirely rather than overriding oslo.log defaults with an empty list.
func renderDefaultLogLevels(perLogger map[string]string) string {
    if len(perLogger) == 0 {
        return ""
    }
    keys := make([]string, 0, len(perLogger))
    for k := range perLogger {
        keys = append(keys, k)
    }
    sort.Strings(keys)
    pairs := make([]string, 0, len(keys))
    for _, k := range keys {
        pairs = append(pairs, fmt.Sprintf("%s=%s", k, perLogger[k]))
    }
    return strings.Join(pairs, ",")
}

func TestReconcileConfig_LoggingPerLoggerLevelsDeterministicOrder(t *testing.T) {
    // ... two specs with the same logical PerLoggerLevels but different
    // map-literal orderings ...
    cmName, err := r.reconcileConfig(context.Background(), ks)
    g.Expect(err).NotTo(HaveOccurred())
    g.Expect(cm.Data["keystone.conf"]).To(ContainSubstring(
        "default_log_levels = amqp=ERROR,keystone.middleware=DEBUG,sqlalchemy.engine=WARNING"))

    // Second reconcile with reordered map literal must produce the same name.
    cm2Name, err := r.reconcileConfig(context.Background(), ks2)
    g.Expect(err).NotTo(HaveOccurred())
    g.Expect(cm2Name).To(Equal(cmName),
        "identical PerLoggerLevels with different map iteration order must yield the same ConfigMap name")
}
